        order = 10
)
public class ExamplePage implements KitPage {
    private JPanel panel;

    public ExamplePage() {
        panel = new JPanel();
        panel.add(new JLabel("Example Page"));
    }

    @Override
    public JPanel getPanel() {
        return panel;
    }
}
```

